def run_twice(func):
    func()
    func()

def clap():
    print("*clap*")

run_twice(clap)

def shout_decorator(func):
    def wrapper():
        print(">>> Getting ready...")
        func()
        print("<<< Done!")
    return wrapper

@shout_decorator          # same as: greet = shout_decorator(greet)
def greet():
    print("Hi there!")

greet()

import functools

@functools.lru_cache(maxsize=128)
def fibonacci(n):
    if n < 2:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

print(fibonacci(35))

