import functools

def require_positive(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        for arg in args:
            if arg <= 0:
                print(f"Error: all arguments must be positive, got {arg}")
                return None
        return func(*args, **kwargs)
    return wrapper

@require_positive
def divide(a, b):
    return a / b

print(divide(10, 2))   # 5.0
print(divide(10, -1))  # Error: all arguments must be positive, got -1 / None
print(divide(0, 5))    # Error: all arguments must be positive, got 0 / None
